import torch
import torch.nn as nn

class CustomLoss(nn.Module):
    def __init__(self, class_weights):
        super().__init__()
        # BUG: class_weights are a plain list -> stored as CPU tensor
        # even when the model is moved to CUDA.
        self.weights = torch.tensor(class_weights, dtype=torch.float32)

    def forward(self, logits, targets):
        # logits on cuda:0, self.weights on cpu -> mismatched matmul
        weighted = logits @ torch.diag(self.weights)
        return nn.functional.cross_entropy(weighted, targets)

class Model(nn.Module):
    def __init__(self):
        super().__init__()
        self.backbone = nn.Linear(768, 512)
        self.head = nn.Linear(512, 10)

    def forward(self, x):
        return self.head(torch.relu(self.backbone(x)))

def train_step():
    model = Model().cuda()
    loss_fn = CustomLoss([1.0, 2.0, 1.5] + [1.0] * 7)
    x = torch.randn(128, 768, device='cuda:0')
    y = torch.randint(0, 10, (128,), device='cuda:0')
    logits = model(x)
    loss = loss_fn(logits, y)
    loss.backward()

if __name__ == '__main__':
    train_step()
